import{_ as e,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Xiaomi Pre-Install","description":"","frontmatter":{"title":"Xiaomi Pre-Install","slug":"xiaomi-pre-install"},"headers":[],"relativePath":"developer-hub/xiaomi-pre-install.md","filePath":"developer-hub/xiaomi-pre-install.md"}'),s={name:"developer-hub/xiaomi-pre-install.md"};function o(r,a,l,p,d,c){return t(),n("div",null,[...a[0]||(a[0]=[i(`<p><em>[Image: 636]</em></p><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Branch partners with Xiaomi in order to support preload/pre-install attribution of your app&#39;s campaigns. Enabling support for this attribution will allow you to properly measure the full lifecycle of your customer before they make their first few conversions in the app.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>In order to attribute pre-installs, you need to have completed the following:</p><ul><li>Implement the latest version of the Branch <a href="./android-basic-integration.html">Android SDK</a> into your app.</li></ul><h3 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><h3 id="_1-initiate-campaign-setup" tabindex="-1">1. Initiate Campaign Setup <a class="header-anchor" href="#_1-initiate-campaign-setup" aria-label="Permalink to &quot;1. Initiate Campaign Setup&quot;">​</a></h3><p>To initialize the campaign for Xiaomi, you will need to gather the following:</p><table tabindex="0"><thead><tr><th>What</th><th>Obtained From</th><th>Description</th></tr></thead><tbody><tr><td><code>$3p</code> Value</td><td>Branch Account Manager</td><td>Contact your Branch account manager to set up the <code>$3p</code> value: <code>a_xiaomipai</code> for the campaign</td></tr><tr><td>Campaign Name</td><td>Customer</td><td>Contact the customer in order to get the name of the campaign</td></tr></tbody></table><h3 id="_2-add-ispreinstallapp-method-to-your-app" tabindex="-1">2. Add <code>isPreinstallApp()</code> Method to your App <a class="header-anchor" href="#_2-add-ispreinstallapp-method-to-your-app" aria-label="Permalink to &quot;2. Add \`isPreinstallApp()\` Method to your App&quot;">​</a></h3><p>You will need to create a method called <code>isPreinstallApp()</code> for the Android app to determine whether the application is a pre-installed application</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public static boolean isPreinstallApp(String pkgName) { </span></span>
<span class="line"><span>try {</span></span>
<span class="line"><span>    Class&lt;?&gt; miui = Class.forName(&quot;miui.os.MiuiInit&quot;);</span></span>
<span class="line"><span>    Method method = miui.getMethod(&quot;isPreinstalledPAIPackage&quot;, String.class);</span></span>
<span class="line"><span>    return (Boolean) method.invoke(null, pkgName); } catch (Exception e) {</span></span>
<span class="line"><span>    Log.e(TAG, &quot;isPreinstalledPAIPackage failed:&quot;, e); }</span></span>
<span class="line"><span>    return false;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_3-call-method-in-oncreate" tabindex="-1">3. Call Method in <code>onCreate()</code> <a class="header-anchor" href="#_3-call-method-in-oncreate" aria-label="Permalink to &quot;3. Call Method in \`onCreate()\`&quot;">​</a></h3><p>Once you have created the <code>isPreinstallApp()</code> method, you will need to call it in your <code>onCreate()</code> method of the Android App.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Override</span></span>
<span class="line"><span>    public void onCreate() {</span></span>
<span class="line"><span>        super.onCreate();</span></span>
<span class="line"><span>        // Branch object initialization</span></span>
<span class="line"><span>        Branch branch = Branch.getAutoInstance(this);</span></span>
<span class="line"><span>        if(isPreinstallApp(getPackageName())){</span></span>
<span class="line"><span>            branch.setPreinstallCampaign(&quot;xiaomipai_test_campaign&quot;);</span></span>
<span class="line"><span>            branch.setPreinstallPartner(&quot;a_xiaomipai&quot;);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span></code></pre></div><p>Don&#39;t forget to release the app to the play store.</p><h3 id="_4-enable-xiaomi-in-branch" tabindex="-1">4. Enable Xiaomi in Branch <a class="header-anchor" href="#_4-enable-xiaomi-in-branch" aria-label="Permalink to &quot;4. Enable Xiaomi in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt; Partner Management</strong>, find/search for Xiaomi Airpreload. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_xiaomipai?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p><em>[Image: 1483]</em></p><h3 id="_5-view-data-in-branch" tabindex="-1">5. View Data in Branch <a class="header-anchor" href="#_5-view-data-in-branch" aria-label="Permalink to &quot;5. View Data in Branch&quot;">​</a></h3><p>As campaigns run, you will be able to measure the performance of the pre-install analytics directly on the Branch Dashboard.</p><p><em>[Image: 1507]</em></p>`,23)])])}const u=e(s,[["render",o]]);export{m as __pageData,u as default};
